// Problem 21: Reduce Sum
// Use .reduce() to calculate the total sum of an array of numbers.
const sumNums = [10, 20, 30, 40];
const totalSum = sumNums.reduce((sum, curr)=> sum+curr,0)
console.log("Problem 21:", totalSum);

// Problem 22: Reduce Max
// Use .reduce() to find the maximum number in an array without using Math.max().
const maxNums = [15, 50, 22, 90, 4];
const maxVal = maxNums.reduce((max, curr)=>{
  if(max < curr) max = curr;
  return max;
},maxNums[0])
console.log("Problem 22:", maxVal);

// Problem 23: Object Tally
// Given an array of fruits, use .reduce() to return an object counting them.
const fruits = ["apple", "banana", "apple", "orange", "banana", "apple"];
const fruitTally = fruits.reduce((obj, curr)=>{
  if(!obj[curr]) obj[curr] = 1;
  else obj[curr] += 1;
  return obj;
},{})
console.log("Problem 23:", fruitTally); // Expected: { apple: 3, banana: 2, orange: 1 }

// Problem 24: Chaining Methods
// Chain .filter() to remove negative numbers, then chain .map() to multiply the remaining numbers by 10.
const chainNums = [-5, 10, -2, 20, 3];
const chainedResult = chainNums.filter(d=>d>0).map(d=>d*10)
console.log("Problem 24:", chainedResult);

// Problem 25: Cart Total
// Given an array of shopping cart objects, use .reduce() to calculate the total price.
const cart = [
  { product: "Book", price: 20 },
  { product: "Pen", price: 5 },
  { product: "Notebook", price: 10 },
];
const cartTotal = cart.reduce((total, curr)=> total + curr.price, 0)
console.log("Problem 25:", cartTotal);
